VALUES
  ('locality-d0d1b9a2-moex-00114', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X6年1月1日流通在外普通股股數為100,000股，7月1日發行新股60,000股，10 月1日發行5%，面額$100，可轉換公司債400張，每張可轉換成15股普通股，該公司債具 稀釋作用，則甲公司在計算X6年稀釋每股盈餘時，其加權平均流通在外普通股股數為：', '["161,500股", "160,000股", "131,500股", "130,000股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00115', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲冷氣公司於X2年1月1日與乙電器行簽訂銷售合約，每台售價$20,000，成本$10,000。但 若乙電器行於該年內購買超過20台冷氣，則合約明定每台單價將減少為$17,000（並追溯至 當年度已售出之前10台），並應於確定超過10台時讓乙電器行抵繳應支付之現金。甲冷氣 公司於X2年第一季，銷售5台冷氣予乙電器行並收取現金。甲冷氣公司估計，乙電器行於 該年不會購買超過10台。試問甲冷氣公司第一季應認列的銷貨收入金額為何？', '["$85,000", "$100,000", "$170,000", "$200,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00116', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初向乙公司租賃一台機器，簽訂5年期租約，每期租金$60,000於年初支付。乙公 司的隱含利率為 5%，且為甲公司所知，而甲公司的增額借款利率為 6%。甲公司在租約結束時有 保證殘值$10,000，另有權可以$12,000之購買價格取得資產所有權（購買選擇權），甲公司無法合 理確定該購買選擇權將被行使，此一機器在租賃結束時，甲公司預期將就保證殘值支付$8,000。試 問X1年初甲公司帳上的使用權資產為多少？（P =3.546,P =3.465,p =0.783,p =0.747） 4,5% 4,6% 5,5% 5,6%', '["$279,024", "$273,876", "$272,760", "$267,900"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00117', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '以間接法編製現金流量表時，下列何者應列為營業活動現金流量中本期損益之加項？', '["預付退休金之增加數", "採權益法處理之權益投資工具產生之投資收益", "按員工認股計畫所認列之酬勞費用", "透過其他綜合損益按公允價值衡量之金融資產，期末依公允價值變動而導致的未實現損失 50420"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00118', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司之存貨管理採用定期盤存制，X3年第一季該公司與存貨相關之資料如下： 期初存貨 $150,000 進貨 450,000 進貨運費 15,000 甲公司當年度之銷貨為$725,000，銷貨退回為$36,000。該公司固定以成本加30%為商品之售 價。試問依毛利率法估計之期末存貨金額為何？', '["$132,700", "$92,500", "$85,000", "$70,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00119', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年初購買設備一部，成本$500,000，耐用年限10年，估計無殘值。甲公司以直 線法提列折舊。該設備於X2年底有減損跡象，甲公司估計該設備之相關資訊如下： 使用價值 $400,000 公允價值減處分成本 380,000 估計殘值 0 該設備之估計耐用年限不變（剩餘耐用年限9年），試計算X2年底甲公司應認列之減損損 失與X3年度之折舊費用（假設該設備未曾辦理重估價）：', '["X2年減損損失$70,000，X3年折舊費用$42,222", "X2年減損損失$70,000，X3年折舊費用$0", "X2年減損損失$50,000，X3年折舊費用$44,444", "X2年減損損失$0，X3年折舊費用$50,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00120', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '下列關於投資性不動產之敘述，有幾項為正確？①待處分之自用不動產屬於投資性不動產的', '["尚未決定未來用途之土地屬於投資性不動產的一種", "原採用成本模式評價之投 資性不動產，後改為依公允價值評價，應依會計政策變動處理", "依公允價值模式評價之投 資性不動產，因公允價值變動產生之利得或損失，應於發生時認列於其他綜合損益  ⑤採公 允價值模式評價之投資性不動產，在轉列為存貨時，應根據用途改變日之公允價值為存貨之 成本，後續依存貨之規定處理", "二項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00121', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年初承攬一項建造工程，價格$200,000，預定X2年底完工。該合約之結果可合理估 計，2年的相關資料如下。試問在完工比例法下，X1年底資產負債表上顯示的合約資產為何？ X1年 X2年 已完成之合約成本 $120,000 $40,000 估計總成本 160,000 160,000 當年度請款金額 120,000 80,000 當年度實際收款金額 100,000 100,000', '["$150,000", "$30,000", "$120,000", "$0 50420"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00122', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '下列關於財務資訊品質特性之敘述，何者錯誤？', '["審慎性之運用可支持資訊之中立性。審慎性之運用指的是對費損與收益須有不對稱的認列 方法。例如無形資產有減損時應認列損失，增值時不能認列利益", "員工挪用一百萬元之公款，對有上百億資產的公司來說，應屬重大之攸關資訊", "對於無法觀察的估計價值，若為選擇及運用適當程序正確發展而得，且清楚說明該金額為 一估計數，並解釋估計程序之性質與限制，則該金額為忠實表述之資訊", "具攸關性之資訊就是能讓使用者做的決策有所不同的資訊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00123', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司自建廠房支出如下：鋼筋水泥等原物料支出$150,000，直接人工$500,000，分攤的間 接成本$60,000，建築師廠房設計費$50,000，與興建廠房有關之專案借款$800,000，其專案借 款成本為$20,000，設算之利息成本為$30,000。試問該自建廠房之成本為何？', '["$810,000", "$780,000", "$760,000", "$710,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
